import{_ as e,o as p,c as r,a9 as o}from"./chunks/framework.D4xYp1Zt.js";const a="/images/taming-mammoth-let-peoples-opinions-run-life/Mammoth1.png",n="/images/taming-mammoth-let-peoples-opinions-run-life/4-shirts-1-1024x705.png",i="/images/taming-mammoth-let-peoples-opinions-run-life/4-shirts-2-1024x703.png",m="/images/taming-mammoth-let-peoples-opinions-run-life/4-shirts-3-1024x694.png",s="/images/taming-mammoth-let-peoples-opinions-run-life/4-shirts-4-1024x733.png",l="/images/taming-mammoth-let-peoples-opinions-run-life/ask-girl-1-1024x699.png",g="/images/taming-mammoth-let-peoples-opinions-run-life/ask-girl-2-1024x791.png",h="/images/taming-mammoth-let-peoples-opinions-run-life/ask-girl-3-1024x785.png",c="/images/taming-mammoth-let-peoples-opinions-run-life/ask-girl-4-1024x785.png",u="/images/taming-mammoth-let-peoples-opinions-run-life/ask-girl-5-1024x763.png",w="/images/taming-mammoth-let-peoples-opinions-run-life/singing-1-1024x785.png",f="/images/taming-mammoth-let-peoples-opinions-run-life/singing-21-1024x819.png",_="/images/taming-mammoth-let-peoples-opinions-run-life/brag-700x1024.png",b="/images/taming-mammoth-let-peoples-opinions-run-life/frat1-1024x443.png",d="/images/taming-mammoth-let-peoples-opinions-run-life/diploma-1-1024x720.png",k="/images/taming-mammoth-let-peoples-opinions-run-life/diploma-2-1024x780.png",y="/images/taming-mammoth-let-peoples-opinions-run-life/puppet-master-1024x785.png",A="/images/taming-mammoth-let-peoples-opinions-run-life/AV-1024x623.png",V="/images/taming-mammoth-let-peoples-opinions-run-life/AV-small-1024x623.png",x="/images/taming-mammoth-let-peoples-opinions-run-life/low-blow-1-1024x785.png",S="/images/taming-mammoth-let-peoples-opinions-run-life/low-blow-2-1024x666.png",T="/images/taming-mammoth-let-peoples-opinions-run-life/low-blow-3-1024x666.png",P="/images/taming-mammoth-let-peoples-opinions-run-life/low-blow-4-1024x620.png",q="/images/taming-mammoth-let-peoples-opinions-run-life/meet-AV1.png",W="/images/taming-mammoth-let-peoples-opinions-run-life/mammoth-hiding-1024x785.png",M="/images/taming-mammoth-let-peoples-opinions-run-life/ousted1-962x1024.png",B="/images/taming-mammoth-let-peoples-opinions-run-life/circles.png",v="/images/taming-mammoth-let-peoples-opinions-run-life/circles-2-1024x785.png",C="/images/taming-mammoth-let-peoples-opinions-run-life/eating-words-1-1024x785.png",O="/images/taming-mammoth-let-peoples-opinions-run-life/eating-words-2-1024x785.png",D="/images/taming-mammoth-let-peoples-opinions-run-life/eating-words-3-1024x710.png",E="/images/taming-mammoth-let-peoples-opinions-run-life/Earth-1024x785.png",L="/images/taming-mammoth-let-peoples-opinions-run-life/die-1024x561.png",G="/images/taming-mammoth-let-peoples-opinions-run-life/toe-in-water-1024x599.png",Y="/images/taming-mammoth-let-peoples-opinions-run-life/medium-mammoth1.png",$="/images/taming-mammoth-let-peoples-opinions-run-life/small-mammoth.png",j="/images/taming-mammoth-let-peoples-opinions-run-life/wbw-mammoth-plushie-01-300x300.jpg",F="/images/taming-mammoth-let-peoples-opinions-run-life/pinit_fg_en_rect_gray_20.png",H=JSON.parse('{"title":"Taming the Mammoth: Why You Should Stop Caring What Other People Think","description":"","frontmatter":{"title":"Taming the Mammoth: Why You Should Stop Caring What Other People Think","titleZh":"驯服猛犸:为何不该在意他人看法","date":"2014-06-13T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html","slug":"taming-mammoth-let-peoples-opinions-run-life"},"headers":[],"relativePath":"posts/taming-mammoth-let-peoples-opinions-run-life.md","filePath":"posts/taming-mammoth-let-peoples-opinions-run-life.md","lastUpdated":1782886257000}'),N={name:"posts/taming-mammoth-let-peoples-opinions-run-life.md"};function I(R,t,U,Z,J,K){return p(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="驯服猛犸-为何不该在意他人看法-·-taming-the-mammoth-why-you-should-stop-caring-what-other-people-think" tabindex="-1">驯服猛犸:为何不该在意他人看法 · Taming the Mammoth: Why You Should Stop Caring What Other People Think <a class="header-anchor" href="#驯服猛犸-为何不该在意他人看法-·-taming-the-mammoth-why-you-should-stop-caring-what-other-people-think" aria-label="Permalink to &quot;驯服猛犸:为何不该在意他人看法 · Taming the Mammoth: Why You Should Stop Caring What Other People Think&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html</a> · 2014-06-13</p></blockquote><p><em>我们把这篇文章做成了一个精美的 PDF,方便打印和离线阅读。<a href="https://gum.co/wbw-mammoth" target="_blank" rel="noreferrer">点这里购买</a>。</em></p><p><strong>第一部分:认识一下你的猛犸象</strong></p><p>上二年级的第一天,我到学校后发现班里多了一个非常漂亮的新女孩——前两年都没见过她。她叫 Alana,不到一个小时,她就成了我生命的全部。</p><p>当你 7 岁的时候,喜欢上一个人其实并没什么可行的下一步动作。你甚至都搞不清楚自己想要什么。就是有那么一种模糊的向往,成了你生活的一部分,仅此而已。</p><p>但几个月后,这事儿突然变得非常紧迫。有一天课间休息时,班里一个女孩开始挨个问每个男生:“你想娶<em>谁谁谁</em>?”问到我时,答案不言自明。“Alana。”</p><p>灾难。</p><p>我当时还是个刚上路的人类,不知道<em>唯一</em>社会可接受的答案是 <em>“谁都不娶”</em>。</p><p>我话音刚落,这个恶毒的女孩就冲向其他同学,挨个告诉他们:“Tim 说他想娶 <em>Alana</em>!”每个听到的人都捂着嘴笑得停不下来。我完了。人生结束了。</p><p>消息很快传到了 Alana 本人耳中,接下来的好几天她都离我远远的。要是她知道什么叫限制令,她估计早就申请一个了。</p><p>这段可怕的经历教给了我一个至关重要的人生教训——做自己可能会有致命危险,任何时候都要在社交上极度谨慎。</p><p>现在听起来这好像只有一个受了创伤的二年级学生才会这么想,但奇怪的是——这也是本文的主题——这个教训并不只局限于我和我那一塌糊涂的童年,<em>它是人类这个物种一个决定性的偏执</em>。我们共享着一种弥漫在世界各地人类文化中的集体疯狂:</p><p><strong>对他人如何看待自己的一种非理性、无意义的执念。</strong></p><p>进化做每件事都有其原因。为了理解这种特殊疯狂的起源,让我们先倒回到公元前 50,000 年的埃塞俄比亚,在那里,你的<a href="https://waitbutwhy.com/2013/12/your-ancestor-is-jellyfish.html" target="_blank" rel="noreferrer">两千代前的曾祖父</a>作为一个小部落的一员生活着。</p><p>在那个年代,归属于一个部落对生存至关重要。部落意味着食物和保护,而在那个年代,这两样东西都不容易得到。所以对你的两千代曾祖父来说,世界上几乎没有什么比被同部落成员接纳更重要了,尤其是那些身居高位的人。融入身边的人、讨好上头的人,意味着他能留在部落里,而他能想象到的最可怕的噩梦,就是部落里的人开始窃窃私语说他有多烦人、多没用、多古怪——因为如果足够多的人不待见他,他在部落中的地位就会下降,如果情况变得非常糟糕,他就会被彻底赶出去,任其自生自灭。他还知道,如果他曾经因为追求部落里的某个姑娘被拒而丢脸,那个姑娘会告诉其他姑娘——他不仅搞砸了跟这个姑娘的机会,而且可能这辈子都找不到伴侣了,因为他生命中将会出现的每一个姑娘都知道了他那次逊爆了的失败尝试。被社会接纳就是<em>一切</em>。</p><p>正因如此,人类进化出了一种对别人怎么看自己的过度痴迷——渴求社会的认可和赞赏,并对被人讨厌怀有一种令人瘫痪的恐惧。我们把这种痴迷叫做人类的社交生存猛犸象 (Social Survival Mammoth)。它长这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/Mammoth1.png" target="_blank" rel="noreferrer"><img src="'+a+'" alt="Mammoth"></a></p><p>你那位两千代曾祖父的社交生存猛犸象是他能忍耐并繁荣的核心。规则很简单——用社会认可把猛犸象喂饱,并密切留意它对不被接纳的巨大恐惧,你就没事。</p><p>在公元前 50000 年,这一切都挺好。公元前 30000 年也是。公元前 10000 年还是。但在过去的一万年里,人类身上发生了一件有点搞笑的事——他们的文明<em>剧烈地</em>变化了。突然、快速的变化是文明所具备的能力,而这之所以让人别扭,是因为我们的进化生物学远远跟不上这个速度。所以在历史的大部分时间里,我们的社会结构和生物学都以蜗牛的速度一起演化和调整,但最近文明发展出了兔子般的速度,而我们的生物学还在慢吞吞地爬着。</p><p>我们的身体和头脑是为公元前 50000 年的部落生活打造的,这给现代人留下了一堆不幸的特征,其中之一就是:在一个&quot;社交生存&quot;已经不再是真实概念的世界里,我们依然痴迷于部落式的社交生存。我们都活在 2014 年,身边却跟着一头巨大的、饥饿的、动不动就受惊的长毛猛犸象,它仍然以为现在是公元前 50000 年。</p><p>不然你怎么会出门前试了四套衣服还不确定该穿哪一套?</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/4-shirts-1.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Trying on Shirts"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/4-shirts-2.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Trying on Shirts"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/4-shirts-3.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="Trying on Shirts"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/4-shirts-4.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Trying on Shirts"></a></p><p>猛犸象关于恋爱被拒的噩梦曾让你的祖先谨慎而机灵,但放在今天,这只会让你变成一个胆小鬼:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/ask-girl-1.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Pursuing a Girl"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/ask-girl-2.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Pursuing a Girl"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/ask-girl-3.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Pursuing a Girl"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/ask-girl-4.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="Pursuing a Girl"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/ask-girl-5.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="Pursuing a Girl"></a></p><p>至于艺术层面的冒险有多恐怖,就更别让猛犸象开口了:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/singing-1.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="Karaoke"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/singing-21.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="singing 2"></a></p><p>猛犸象对社会性不认可的恐惧飓风,在大多数人生活的大多数方面都掺了一脚。它就是让你觉得一个人去餐厅或看电影很怪的那股力量;它就是让家长<em>过分</em>在意孩子去哪所大学的那股力量;它就是让你放弃自己热爱的职业、转而去干一份自己不冷不热但更赚钱的工作的那股力量;它就是让你在还没准备好的时候、跟一个自己并不爱的人结婚的那股力量。</p><p>而且,让你那只极度缺乏安全感的「社交生存猛犸象 (Social Survival Mammoth)」保持冷静和安稳,已经够费劲了,但这只是你的一半职责。这只猛犸象还需要被定期、丰盛地喂养——用赞美、认可,以及那种「我站在任何社会或道德二分法的正确一边」的感觉。</p><p>不然你为什么会在 Facebook 上当那种<a href="https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html" target="_blank" rel="noreferrer">精心打造人设的傻逼</a>?</p><p>或者跟朋友出去的时候忍不住吹牛,虽然你事后每次都后悔?</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/brag.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt="Brag"></a></p><p>社会已经进化到能够容纳这场喂养猛犸象的狂欢,发明了诸如荣誉、头衔和&quot;声望&quot;这种概念,来让我们的猛犸象保持满足——而且通常还用来激励人们去做那些毫无意义的工作、过那些原本根本不会考虑参与的乏味人生。</p><p>最重要的是,猛犸象想要合群——这正是部落成员一直以来必须做到的事,所以它们就是被这么编程的。猛犸象环顾社会,搞清楚自己&quot;应该&quot;做什么,一旦搞清楚,就一头扎进去。你只要看看任意两张相隔十年的大学兄弟会合照就明白了:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/frat1.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="frat"></a></p><p>或者看看那些亚文化圈子,里头<em>每一个人</em>拿的都是那三种社会认可的高级学位之一:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/diploma-1.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="Diploma"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/diploma-2.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt="Diploma"></a></p><p>有时候,猛犸象的关注焦点不在广义的社会上,而更多地放在赢得你生命中某位&quot;操纵者 (Puppet Master)&quot;的认可上。操纵者是这样一个人或一群人:他们的看法对你<em>太</em>重要了,以至于本质上是他们在替你过日子。操纵者通常是父母,或者是你的另一半,有时是你朋友圈里的头号人物。操纵者也可能是一个你崇拜但并不太熟的人——甚至是一个你从未见过的名人——或者一群你特别推崇的人。</p><p>我们比渴望任何人都渴望操纵者的认可,一想到会惹操纵者不高兴、感受到他们的不接纳或嘲笑,我们就吓得不行,愿意做任何事来避免这一切。当我们和操纵者的关系走到这种病态状态时,那个人的存在就笼罩着我们整个决策过程,牵动着我们的观点和道德声音的每一根丝线。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/puppet-master.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="puppet master"></a></p><p>当这么多的心思和精力都投入到照顾猛犸象的需求上时,你脑子里往往就有另外一个人被冷落了——那个一直在最中心的人——你的真实之声 (Authentic Voice)。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/AV.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt="AV"></a></p><p>你的「真实自我之声 (Authentic Voice)」深藏在你内心深处的某个地方,它对你了如指掌。相比社交生存猛犸象那种非黑即白的简单头脑,你的「真实自我之声」是复杂的、有时模糊的、不断演变的、无所畏惧的。你的 AV 有自己一套细腻的道德准则,是由经验、反思,以及它对慈悲与正直的独特理解共同塑造的。它知道你在金钱、家庭、婚姻这些事情上心底真正的想法,它知道你真正喜欢什么样的人、什么话题、什么活动,又对什么不感冒。你的 AV 知道它<em>并不</em>知道你的人生会怎样、应该怎样展开,但它对下一步该怎么走,往往有着强烈的直觉。</p><p>而当猛犸象在做决定时只会向外部世界寻找答案,你的「真实自我之声」会利用外部世界来学习和收集信息——但真正到了做决定的时候,它需要的所有工具就在你大脑深处,现成的。</p><p>你的 AV 也是那种通常会被猛犸象完全无视的存在。外面世界某个自信满满的人给出一个强硬的意见?猛犸象立马竖起耳朵。但你的 AV 慷慨激昂地陈情,基本会被无视,除非有别人跳出来附和一下。</p><p>而且因为我们这颗 5 万年老的大脑天生就给猛犸象很大话语权,你的「真实自我之声」开始觉得自己无关紧要。于是它开始萎缩、褪色、失去动力。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/AV-small.png" target="_blank" rel="noreferrer"><img src="'+V+'" alt="AV"></a></p><p>到最后,一个被猛犸象操控的人可能会彻底与自己的 AV 失去联系。</p><p>在部落时代,AV 常常在默默无闻中度过一生,这基本上没什么问题。那时候生活很简单,合群才是目标——而猛犸象把合群这事儿处理得妥妥的。</p><p>但在如今这个庞大、复杂、充满不同文化、性格、机会与选项的世界里,与你的 AV 失联就很危险了。当你不知道自己是谁,你剩下的唯一决策机制就是猛犸象那套粗糙又过时的需求和情绪。面对那些最私人的问题,你不会深入到自己内心那片朦胧的核心去挖掘你真正相信的东西以获得清晰,而是会转向别人寻找答案。你是谁,变成了周围最强势的那些意见的某种混合物。</p><p>与 AV 失联还会让你变得脆弱,因为当你的身份认同建立在他人的认可之上,被批评或被拒绝就会<em>真的</em>很痛。糟糕的分手对谁都痛,但对一个被猛犸象操控的人来说,它刺入的地方要比对一个有着强大 AV 的人深得多。强大的 AV 构成一个稳固的内核,分手之后,那个内核依然屹立不倒——但对一个被猛犸象操控的人来说,他人的接纳就是他拥有的全部,所以被一个了解你的人甩掉,会是一次远为毁灭性的经历。</p><p>同样地,你知道那种被批评时会用恶毒的下三滥招数反击的人吧?那些人往往是被猛犸象严重支配的人,批评让他们如此愤怒,是因为猛犸象受不了批评。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/low-blow-1.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt="Low Blow"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/low-blow-2.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt="Low Blow"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/low-blow-3.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt="Low Blow"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/low-blow-4.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt="Low Blow"></a></p><p>到这里,任务应该已经很明确了——我们得想办法绕过大脑的既有布线,驯服这头猛犸象。这是把生活夺回来的唯一办法。</p><p><strong>第二部分:驯服猛犸象</strong></p><p>有些人天生就带着一头相对温顺的猛犸象,或是被父母教得好、猛犸象一直被约束着。也有些人到死都没能勒住自己的猛犸象,一辈子都活在它的心血来潮之下。我们大多数人处在中间地带——在生活的某些领域里管住了猛犸象,但在另一些领域里它照样撒野。被猛犸象牵着走并不代表你是个坏人或懦弱的人——只是说明你还没搞清楚怎么抓住它的缰绳。你甚至可能根本没意识到自己有一头猛犸象,也没意识到你的「本真之声 (Authentic Voice)」被压制到了什么程度。</p><p>不管你的情况如何,把猛犸象控制住有三个步骤:</p><p><strong>第一步:审视自己</strong></p><p>改善局面的第一步,是对你脑子里到底在发生什么,做一次清晰而诚实的评估,这里面又分三部分:</p><p><strong>1)认识你的本真之声</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/meet-AV1.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt="meet AV"></a></p><p>听起来不难,其实很难。要拨开层层叠叠的他人想法与观点、找出真正的你,得下点认真的反思功夫。你跟很多人打交道——他们当中你其实最喜欢的是谁?你的空闲时间怎么打发,里面每一部分你都真心享受吗?有没有什么你经常花钱、但花得并不那么舒坦的事情?对自己的工作和感情状态,你内心真实的感受是什么?你真正的政治立场是什么?你到底在不在乎?你会不会为了显得有观点,而假装在乎某些其实无所谓的事?你有没有某个关于政治或道德议题的观点,因为怕认识的人炸毛,就一直藏在心里不敢说出口?</p><p>对于这个过程,有一些老掉牙的说法——「灵魂探索」或「寻找自我」——但事情就该是这样。也许你可以就坐在现在这把椅子上反思,或者从日常生活的某个片段中反思——又或者你需要一个人跑到很远的地方,跳出自己的生活,才能有效地审视它。不管怎样,你都必须搞清楚什么对你来说<em>真正</em>重要,并开始为你的真实之声(Authentic Voice)——不管它是什么样——感到自豪。</p><p><strong>2) 找出猛犸象藏在哪里</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/mammoth-hiding.png" target="_blank" rel="noreferrer"><img src="'+W+'" alt="mammoth hiding"></a></p><p>大多数时候当一头猛犸象控制着一个人,这个人其实并不自知。但如果你没能清清楚楚看到最大的问题区域在哪,你就没法取得任何进展。</p><p><strong>找到猛犸象最明显的方法就是找到你的恐惧在哪里</strong>——你在什么方面最容易感到羞耻或尴尬?生活中的哪些部分只要一想到就会让你产生一种可怕的下沉感?哪里失败的可能性听起来像噩梦?什么事你明知自己擅长,却胆怯得不敢公开尝试?如果你是给自己提建议的那个人,你生活中哪些部分明显需要改变,而你现在却回避着不去行动?</p><p>**猛犸象藏身的第二个地方,是那种被别人接纳、或者凌驾于他人之上时产生的过度良好的感觉。**你在工作或感情中是个严重的<em>讨好者</em>吗?你是不是特别怕让父母失望,总是选择让他们骄傲而不是让自己满足?你会不会因为跟一些有声望的东西沾上边而过于兴奋,或者太在意地位?你是不是吹嘘得比该有的程度多?</p><p>**猛犸象出现的第三个地方,是任何你没有他人的「许可」或认可就没法舒服做决定的场合。**你是不是有些观点其实是从别人嘴里抄来的,只是因为知道那个人这么想,你才觉得自己这么想是安全的?当你第一次把新男/女朋友介绍给朋友或家人时,他们对这个人的反应会不会从根本上改变你对他/她的感觉?你的生活中有没有一位「操纵者」?如果有,是谁,为什么?</p><p><strong>3) 决定猛犸象需要在哪些地方被赶走</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/ousted1.png" target="_blank" rel="noreferrer"><img src="'+M+'" alt="ousted"></a></p><p>想把猛犸完全从脑袋里赶出去是不现实的——你是人,人的脑子里就有猛犸,就这么回事。我们所有人真正要做的,是划出生命中某些神圣的领域,这些领域<em>必须</em>由 AV 掌控,不受猛犸的影响。有些领域显然应该纳入 AV 的地盘,比如你选择的人生伴侣、你的职业道路、你养育孩子的方式。其他的则因人而异——归根结底是这个问题:「在生活的哪些部分,你必须完全忠于自己?」</p><p><strong>第二步:通过内化「猛犸智商很低」这一事实来鼓起勇气</strong></p><p>真正的猛犸象已经没什么本事,都灭绝了,社会生存猛犸也好不到哪儿去。尽管它们把我们折磨得够呛,但我们的猛犸其实是愚蠢、原始的生物,对现代世界毫无理解。深刻理解这一点——并<em>内化</em>它——是驯服你自己那只猛犸的关键一步。有两个重要的理由让你不必把猛犸当回事:</p><p><strong>1) 猛犸的恐惧完全不理性。</strong></p><p>猛犸搞错的 5 件事:</p><p>→ <strong>每个人都在议论我和我的生活,想想看,如果我做了这件冒险或奇怪的事,大家该议论得多起劲啊。</strong></p><p>猛犸眼中的世界是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/circles.png" target="_blank" rel="noreferrer"><img src="'+B+'" alt="circles"></a></p><p>实际情况是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/circles-2.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt="Circle"></a></p><p>其实没人真的那么在意你在干什么。人们高度地自我中心。</p><p>→ <strong>只要我足够努力,就能取悦所有人。</strong></p><p>是的,也许在一个 40 人、文化统一的部落里可以。但在今天这个世界,不管你是谁,总会有一群人喜欢你,另一群人不喜欢你。被某一类人认可就意味着让另一类人反感。所以执着于融入某一个群体是不合逻辑的,尤其是当那个群体根本不代表真正的你。你费尽心力,而与此同时,你真正合得来的那些人正在别处彼此做朋友呢。</p><p>→ <strong>被人不认可、被看不起或被背后说坏话,会对我的生活造成真实的后果。</strong></p><p>任何不认可你为人或不认可你所作所为的人,99.7% 的时间根本都不在你身边。猛犸的一个经典错误就是:虚构出一幅未来社会后果的画面,这幅画面比实际发生的情况<em>糟糕得多</em>——而实际发生的通常什么都没有。</p><p>→ <strong>那些特别爱评判人的人很重要。</strong></p><p>爱评判他人的人是这样运作的:他们高度受猛犸象控制,然后跟其他同样高度受猛犸象控制、爱评判他人的人做好朋友、谈恋爱。他们在一起做的主要活动之一,就是说不在场的人的坏话——也许他们心里有点嫉妒,而翻白眼式的鄙视能帮他们扭转心态、减轻嫉妒感;或者他们并不嫉妒,只是把某个人当作沉浸于<a href="https://en.wikipedia.org/wiki/Schadenfreude" target="_blank" rel="noreferrer">幸灾乐祸 (schadenfreude)</a>的载体——但不管底层情绪是什么,这种评判都是在喂他们那头饥饿的猛犸象。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/eating-words-1.png" target="_blank" rel="noreferrer"><img src="'+C+'" alt="eating words 1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/eating-words-2.png" target="_blank" rel="noreferrer"><img src="'+O+'" alt="eating words 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/eating-words-3.png" target="_blank" rel="noreferrer"><img src="'+D+'" alt="eating words 3"></a></p><p>当人们说别人坏话时,他们其实是划出了一条阵营分界线,而他们永远站在正确的那一边。他们这么做是为了把自己抬上一个台座,好让他们的猛犸象在上面大快朵颐。</p><p>想到自己成了某个爱评判者用来自我感觉良好的原料,是挺让人火大的——但这其实没有任何实际后果,而且这件事显然更多是关于那个爱评判的人和他们的猛犸象问题,而不是关于你。如果你发现自己做决定时,一部分动机是为了不被某个爱评判的人说坏话,那就好好想想到底发生了什么,然后停下来。</p><p>→ <strong>如果我让爱我、为我付出很多的人失望或不快,我就是个坏人。</strong></p><p>不。做你这一辈子里那个真实的自己,并不会让你成为坏人。这是那种很简单的事——如果他们真的无私地爱你,那么一旦看到你过得开心,他们最终一定会接受一切。如果你已经很开心,他们却还是没转过弯来,那么真相是:他们对你该成为什么样的人、该做什么事的强烈看法,<em>说话的其实是他们的猛犸象</em>,他们的主要动机是担心这在认识他们的其他人眼里会“显得”怎样。他们让自己的猛犸象凌驾于对你的爱之上,你应该态度坚决地无视他们。</p><p>猛犸象对社会认同的恐惧执念之所以说不通,还有另外两个原因:</p><p><strong>A) 你住在这里:</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/Earth.png" target="_blank" rel="noreferrer"><img src="'+E+'" alt="Earth"></a></p><p>所以谁他妈还在乎什么啊?</p><p><strong>B) 你和你认识的每一个人都会死。还挺快的。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/die.png" target="_blank" rel="noreferrer"><img src="'+L+'" alt="die"></a></p><p>所以就……是啊。</p><p>猛犸象的恐惧不理性,这是它智商低下的一个原因。第二个原因是:</p><p><strong>2)猛犸象的努力适得其反。</strong></p><p>整件事的讽刺之处在于,这只强迫症般笨重前行的猛犸象连自己的本职工作都做不好。它那套赢得认可的方法在更简单的时代或许有效,但如今显得笨拙又令人反感。现代世界是 AV(真实自我)的世界,如果猛犸象想在社交上如鱼得水,它就该去做那件最让它害怕的事——把主导权交给 AV。原因如下:</p><p><strong>AV 有趣,猛犸象无聊。</strong> 每个 AV 都是独特而复杂的,这本身就是有趣的。猛犸象则千篇一律——它们抄袭、随大流,动机不基于任何真实或本真的东西,只是在做它们觉得自己&quot;应该&quot;做的事。这无聊到极点。</p><p><strong>AV 引领,猛犸象跟随。</strong> 领导力对大多数 AV 来说是天生的,因为他们的思想和观点源自一个原创的地方,这给了他们一个原创的视角。而如果他们足够聪明和有创造力,他们就能改变世界上的事物,发明能颠覆现状的东西。如果你给某人一支画笔和一张空白画布,他们画出来的东西可能不好——但他们总归会以某种方式改变这张画布。</p><p>而猛犸象呢——它们跟随,这是定义使然。它们生来就是干这个的——融入群体、跟着领头者走。猛犸象最不可能做的事就是改变现状,因为它拼命想要<em>成为</em>现状本身。当你给某人一支画笔和一张画布,但颜料和画布是完全一样的颜色时,他们想怎么画就怎么画,但什么都改变不了。</p><p><strong>人们被 AV 吸引,而不是被猛犸象吸引。</strong> 一个被猛犸象控制的人在初次约会时唯一能显得有魅力的场合,就是对方也是个被猛犸象控制的人。AV 强大的人一眼就能看穿被猛犸象控制的人,并对他们毫无兴趣。我一个朋友之前和一个纸面条件很棒的男生约会,但最后分了手,因为她就是喜欢不上他。她试图说清楚为什么,说他不够怪、不够特别——他看起来就像&quot;众多男生中普通的一个&quot;。换句话说,他被猛犸象控制得太厉害了。</p><p>这一点在朋友和同事之间也成立,AV 主导的人更受尊重、更有磁场——不一定是因为他们身上有什么非凡之处,而是因为<em>人们尊重那种有性格力量、能驯服自己猛犸象的人。</em></p><p><strong>第 3 步:开始做你自己</strong></p><p>在&quot;开始做你自己&quot;这句话出现之前,这篇文章都还是有趣的游戏。到目前为止,这是一次有意思的反思:为什么人类如此在意别人的想法、为什么这样很糟、这在你生活中如何成为问题、以及为什么它没有理由继续折磨你。但读完这篇文章后真正去<em>做</em>些什么,就完全是另一回事了。这需要的不止是反思——还需要一些勇气。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/toe-in-water.png" target="_blank" rel="noreferrer"><img src="'+G+'" alt="toe in water"></a></p><p>但是,鼓起勇气去对抗<em>什么</em>呢?正如我们讨论过的,做自己其实并不涉及任何真正的危险——它更多地只是需要一个「皇帝没穿衣服」式的顿悟,简单来说就是:</p><p><strong>你在社交上害怕的几乎所有东西,其实都不可怕。</strong></p><p>把这个想法消化进去,会削弱你所感到的恐惧,而没有了恐惧,猛犸象就失去了一部分力量。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/medium-mammoth1.png" target="_blank" rel="noreferrer"><img src="'+Y+'" alt="medium mammoth"></a></p><p>猛犸象一旦被削弱,你就有可能开始为真实的自己挺身而出,甚至做出一些大胆的改变——而当你看到这些改变结果不错、几乎没什么负面后果、也没什么可后悔的时候,顿悟就被强化了,一个当家做主的 AV 就变成了一种习惯。你的猛犸象已经失去了操控你的能力,它被驯服了。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/06/small-mammoth.png" target="_blank" rel="noreferrer"><img src="'+$+'" alt="small mammoth"></a></p><p>猛犸象还在你身边——它会永远在你身边——但当它开口或撒泼时,你会更容易忽略它或压制它,因为现在 AV 才是头狼。你可以开始享受被别人视为怪咖、不得体或让人费解的感觉,而社会变成了你的游乐场和空白画布,而不是一个你必须卑躬屈膝、乞求认可的对象。</p><p>做出这个转变对谁来说都不容易,但值得为之着迷。你的「真实自我 (Authentic Voice)」只有一次生命——你的任务,就是确保它有机会真正活过一场。</p><hr><p>你可以**<a href="https://gum.co/wbw-mammoth" target="_blank" rel="noreferrer">购买本文的 PDF 版本</a><strong>用于离线分享,或者在</strong><a href="https://store.waitbutwhy.com/collections/plush-toys/products/the-mammoth-plush-toy?variant=19704079361" target="_blank" rel="noreferrer">这里</a>**获取一只你自己的社交生存猛犸象:</p><p><a href="https://store.waitbutwhy.com/collections/plush-toys/products/the-mammoth-plush-toy?variant=19704079361" target="_blank" rel="noreferrer"><img src="'+j+'" alt="WBW mammoth plush toy"></a></p><hr><p><strong>Wait But Why 上更多关于人生与幸福的文章</strong></p><p>你大脑另一部分正在进行的另一场斗争——<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">拖延者为什么拖延</a></p><p>我从埃隆·马斯克 (Elon Musk) 身上学到的、改变了我思考人生方式的东西:<a href="https://waitbutwhy.com/2015/11/the-cook-and-the-chef-musks-secret-sauce.html" target="_blank" rel="noreferrer">厨子与大厨:马斯克的秘方</a></p><p>更深入地看看猛犸象以及你大脑里其他动物的那些事儿。一篇把这一切串起来的文章——<a href="https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html" target="_blank" rel="noreferrer">一种给非宗教人士的宗教</a></p><p>想要幸福,你得知道幸福住在哪儿 —— <a href="https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html" target="_blank" rel="noreferrer">人生是一幅画,但你活在一个像素里</a></p><p>猛犸象不擅长挑选人生伴侣 —— <a href="https://waitbutwhy.com/2014/02/pick-life-partner.html" target="_blank" rel="noreferrer">如何挑选你的人生伴侣</a></p><h2 id="很遗憾-你剩下的星期数并不多。让每一周都有意义。你的人生-以周计" tabindex="-1">很遗憾,你剩下的星期数并不多。让每一周都有意义。<a href="https://waitbutwhy.com/2014/05/life-weeks.html" target="_blank" rel="noreferrer">你的人生,以周计</a> <a class="header-anchor" href="#很遗憾-你剩下的星期数并不多。让每一周都有意义。你的人生-以周计" aria-label="Permalink to &quot;很遗憾,你剩下的星期数并不多。让每一周都有意义。[你的人生,以周计](https://waitbutwhy.com/2014/05/life-weeks.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,我们会在新文章发布时通知你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html&amp;description=Taming%20the%20Mammoth:%20Why%20You%20Should%20Stop%20Caring%20What%20Other%20People%20Think" target="_blank" rel="noreferrer"><img src="'+F+'" alt=""></a></p>',148)])])}const Q=e(N,[["render",I]]);export{H as __pageData,Q as default};
